import { useEffect, useMemo, useState } from 'react';
import ConfirmModal from '../components/common/ConfirmModal';
import SOSButton from '../components/common/SOSButton';
import { triggerSOS } from '../api/sos.api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../components/common/ToastProvider';

function SOS() {
  const { user } = useAuth();
  const { pushToast } = useToast();
  const [location, setLocation] = useState('');
  const [status, setStatus] = useState('idle');
  const [openConfirm, setOpenConfirm] = useState(false);
  const [sending, setSending] = useState(false);
  const [countdown, setCountdown] = useState(60);

  const timeline = useMemo(() => {
    if (status === 'idle') return ['Waiting for SOS trigger'];
    if (status === 'sent') return ['SOS triggered', 'Dispatcher notified', 'Awaiting response'];
    return ['SOS triggered', 'Help dispatched', 'Assistance reached'];
  }, [status]);

  useEffect(() => {
    document.body.classList.toggle('emergency-active', status !== 'idle');
    return () => document.body.classList.remove('emergency-active');
  }, [status]);

  useEffect(() => {
    if (status === 'idle') return undefined;
    setCountdown(60);
    const id = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);
    return () => clearInterval(id);
  }, [status]);

  useEffect(() => {
    if (status === 'idle' || !navigator.geolocation) return undefined;
    const watchId = navigator.geolocation.watchPosition(
      (pos) => setLocation(`${pos.coords.latitude.toFixed(5)}, ${pos.coords.longitude.toFixed(5)}`),
      () => {
        // ignore background update errors
      },
      { enableHighAccuracy: true, maximumAge: 10000, timeout: 10000 }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, [status]);

  useEffect(() => {
    const syncOfflineQueue = async () => {
      const queued = JSON.parse(localStorage.getItem('offline_sos_queue') || '[]');
      if (!queued.length) return;
      const remaining = [];
      for (const item of queued) {
        try {
          await triggerSOS(item);
        } catch {
          remaining.push(item);
        }
      }
      localStorage.setItem('offline_sos_queue', JSON.stringify(remaining));
      if (remaining.length === 0 && queued.length > 0) {
        pushToast('Offline emergency requests synced successfully.', 'success');
      }
    };

    syncOfflineQueue();
    window.addEventListener('online', syncOfflineQueue);
    return () => window.removeEventListener('online', syncOfflineQueue);
  }, [pushToast]);

  const detectLocation = () => {
    if (!navigator.geolocation) {
      pushToast('Geolocation is not supported in this browser.', 'warning');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setLocation(`${pos.coords.latitude.toFixed(5)}, ${pos.coords.longitude.toFixed(5)}`);
        pushToast('Location detected.', 'success');
      },
      () => pushToast('Unable to fetch location. Enter manually.', 'danger')
    );
  };

  const handleTrigger = async () => {
    const payload = {
      userId: user?.id || 0,
      message: 'Emergency SOS triggered',
      location: location || 'Location not provided'
    };

    try {
      setSending(true);
      await triggerSOS(payload);
      setStatus('sent');
      pushToast('SOS alert sent successfully.', 'success');
      setTimeout(() => setStatus('active'), 2500);
    } catch (error) {
      const offline = !error?.response;
      if (offline) {
        const queued = JSON.parse(localStorage.getItem('offline_sos_queue') || '[]');
        queued.push({ ...payload, queuedAt: new Date().toISOString() });
        localStorage.setItem('offline_sos_queue', JSON.stringify(queued));
        pushToast('No internet. Emergency request saved locally.', 'warning');
        setStatus('sent');
        setTimeout(() => setStatus('active'), 2500);
      } else {
        pushToast('Could not send SOS. Please retry.', 'danger');
      }
    } finally {
      setSending(false);
      setOpenConfirm(false);
    }
  };

  return (
    <div className='container py-5'>
      <div className='row justify-content-center'>
        <div className='col-12 col-lg-8'>
          <div className={`card card-soft p-4 text-center ${status !== 'idle' ? 'emergency-mode-card' : ''}`}>
            <h2 className='mb-2'>Emergency SOS</h2>
            <p className='text-muted'>One-click emergency trigger with location sharing.</p>
            {status !== 'idle' && (
              <div className='mb-3'>
                <span className='countdown-chip'>Response ETA: {countdown}s</span>
              </div>
            )}

            <div className='my-4'>
              <SOSButton onClick={() => setOpenConfirm(true)} disabled={sending} large />
            </div>

            <div className='row g-2 align-items-center'>
              <div className='col-md-8'>
                <input
                  className='form-control'
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                  placeholder='Auto-detected or manual location'
                  aria-label='Emergency location'
                />
              </div>
              <div className='col-md-4 d-grid'>
                <button className='btn btn-outline-secondary' onClick={detectLocation}>Auto Detect</button>
              </div>
            </div>

            <div className='timeline-box mt-4 text-start'>
              <h6>Status Tracking</h6>
              <ul className='mb-0'>
                {timeline.map((item) => (
                  <li key={item}>{item}</li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>

      <ConfirmModal
        open={openConfirm}
        title='Confirm SOS Alert'
        body='Do you want to send the SOS alert now? This will notify available responders.'
        confirmText='Send SOS'
        onConfirm={handleTrigger}
        onCancel={() => setOpenConfirm(false)}
        loading={sending}
      />
    </div>
  );
}

export default SOS;
